package ua.university.sms.controller;
import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import ua.university.sms.model.dto.CourseDtos.*;import ua.university.sms.service.CourseService;import java.util.*;
@RestController @RequestMapping("/api/courses") public class CourseController{private final CourseService service;public CourseController(CourseService service){this.service=service;}@PostMapping public ResponseEntity<Response> create(@Valid @RequestBody Request r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));}@GetMapping("/{id}") public Response get(@PathVariable Long id){return service.get(id);}@GetMapping public List<Response> list(@RequestParam(required=false) Long teacherId,@RequestParam(required=false) Integer credits){return service.list(teacherId,credits);}@PutMapping("/{id}") public Response update(@PathVariable Long id,@Valid @RequestBody Request r){return service.update(id,r);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable Long id){service.delete(id);}}
